parameters.text:
Classify this email and draft a reply based on documentation.

Return JSON: {"category": "...", "draft_reply": "..."}

From: {{ $json.body.from }}
Subject: {{ $json.body.subject }}
Body: {{ $json.body }}

parameters.jsCode:
const text = $input.item.json.text;
const cleaned = text.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  const categoryMatch = cleaned.match(/"category"\s*:\s*"([^"]+)"/);
  const replyMatch = cleaned.match(/"draft_reply"\s*:\s*"([\s\S]+?)"\s*\}/);
  parsed = {
    category: categoryMatch ? categoryMatch[1] : 'unknown',
    draft_reply: replyMatch ? replyMatch[1] : 'Thank you for your message.'
  };
}
return { json: parsed };
